#include <iostream>
#include <set>
using namespace std;
set<int> st;
int n,op,len;
int main()
{
    cin>>n;
    while(n--)
    {
        cin>>op>>len;
        if(op==1)
        {
            if(st.find(len)==st.end())
            {
                st.insert(len);
            }
            else{
                cout<<"Already Exist"<<endl;
            }
        }
        else{
            if(st.empty())
            {
                cout<<"Empty"<<endl;
                continue;
            }
            if(st.find(len)!=st.end())
            {
                cout<<len<<endl;
                st.erase(len);
            }
            else{
                set<int>::iterator r=st.upper_bound(len);
                set<int>::iterator l;
                if(r!=st.begin())
                {
                    l=r--;
                }
                else{
                    l=r;
                }
                if(abs(*l-len)<abs(*r-len))
                {
                    cout<<(*l)<<endl;
                    st.erase(l);
                }
                else{
                    cout<<(*r)<<endl;
                    st.erase(r);
                }
            }
        }
    }
    return 0;
}
